from flask import Flask, request, jsonify, session
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
import qrcode
import io
import base64
import secrets
import time
from functools import wraps

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)

# Mock database
users_db = {}
mfa_db = {}

# Mock database functions
def get_user(username):
    return users_db.get(username)

def save_user(username, password_hash, mfa_enabled=False, mfa_secret=None):
    users_db[username] = {
        'password_hash': password_hash,
        'mfa_enabled': mfa_enabled,
        'mfa_secret': mfa_secret
    }

def get_mfa_status(username):
    user = get_user(username)
    return user.get('mfa_enabled', False) if user else False

def get_mfa_secret(username):
    user = get_user(username)
    return user.get('mfa_secret') if user else None

def set_mfa_secret(username, secret):
    if username in users_db:
        users_db[username]['mfa_secret'] = secret

def enable_mfa(username):
    if username in users_db:
        users_db[username]['mfa_enabled'] = True

def verify_totp(secret, token):
    totp = pyotp.TOTP(secret)
    return totp.verify(token, valid_window=1)

def generate_secret():
    return pyotp.random_base32()

def generate_qr_code(secret, username):
    totp_uri = pyotp.totp.TOTP(secret).provisioning_uri(username, issuer_name="MyApp")
    qr = qrcode.QRCode(version=1, box_size=10, border=4)
    qr.add_data(totp_uri)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")
    img_buffer = io.BytesIO()
    img.save(img_buffer)
    img_buffer.seek(0)
    img_base64 = base64.b64encode(img_buffer.getvalue()).decode()
    return img_base64

# Authentication decorator
def require_auth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'username' not in session:
            return jsonify({'error': 'Authentication required'}), 401
        return f(*args, **kwargs)
    return decorated_function

# Login endpoint
@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    user = get_user(username)
    if not user or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    if user.get('mfa_enabled'):
        session['username'] = username
        session['mfa_required'] = True
        return jsonify({'message': 'MFA required', 'mfa_required': True}), 200
    else:
        session['username'] = username
        session['mfa_required'] = False
        return jsonify({'message': 'Login successful', 'mfa_required': False}), 200

# MFA verification endpoint
@app.route('/verify-mfa', methods=['POST'])
def verify_mfa():
    if 'username' not in session or not session.get('mfa_required'):
        return jsonify({'error': 'No MFA session'}), 400
    
    data = request.get_json()
    token = data.get('token')
    
    username = session['username']
    secret = get_mfa_secret(username)
    
    if not secret or not verify_totp(secret, token):
        return jsonify({'error': 'Invalid OTP'}), 401
    
    session['mfa_verified'] = True
    return jsonify({'message': 'MFA verified successfully'}), 200

# Direct login endpoint (skips MFA)
@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    user = get_user(username)
    if not user or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    session['username'] = username
    session['mfa_required'] = False
    session['direct_login'] = True
    
    return jsonify({'message': 'Direct login successful'}), 200

# MFA setup endpoint
@app.route('/setup-mfa', methods=['POST'])
@require_auth
def setup_mfa():
    username = session['username']
    secret = generate_secret()
    set_mfa_secret(username, secret)
    
    qr_code = generate_qr_code(secret, username)
    
    return jsonify({
        'secret': secret,
        'qr_code': qr_code
    }), 200

# Enable MFA endpoint
@app.route('/enable-mfa', methods=['POST'])
@require_auth
def enable_mfa_endpoint():
    data = request.get_json()
    token = data.get('token')
    
    username = session['username']
    secret = get_mfa_secret(username)
    
    if not secret or not verify_totp(secret, token):
        return jsonify({'error': 'Invalid OTP'}), 401
    
    enable_mfa(username)
    return jsonify({'message': 'MFA enabled successfully'}), 200

# Logout endpoint
@app.route('/logout', methods=['POST'])
def logout():
    session.clear()
    return jsonify({'message': 'Logged out successfully'}), 200

# Protected endpoint example
@app.route('/protected', methods=['GET'])
@require_auth
def protected():
    if 'direct_login' in session:
        return jsonify({'message': 'Direct login access granted'}), 200
    
    if session.get('mfa_verified'):
        return jsonify({'message': 'MFA verified access granted'}), 200
    
    return jsonify({'error': 'Access denied'}), 403

# Registration endpoint
@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if get_user(username):
        return jsonify({'error': 'Username already exists'}), 400
    
    password_hash = generate_password_hash(password)
    save_user(username, password_hash)
    
    return jsonify({'message': 'User registered successfully'}), 201

if __name__ == '__main__':
    app.run(debug=False)